const body = $('Webhook').first().json.body || {};
const template = body.templateContent ?? "";

const fullName = body.fullName ?? "";
const parts = fullName.trim().split(/\s+/);
const lastName = parts.length > 0
  ? parts[parts.length - 1].toUpperCase()
  : "";
const firstName = parts.length > 1
  ? parts.slice(0, -1).join(" ")
  : "";

const alumniID = body.studentNumber ?? "";
const program = body.program ?? "";
const gradYear = body.graduationYear ?? "";
const school = body.school ?? "";
const mobile = body.mobile ?? "";
const email = body.email ?? "";

let idPhotoBase64 = body.photo ?? "";
let idSigBase64 = body.esig ?? "";

let logoPhotoBase64 = $input.first().json.data ?? "";
let logoPhotoMimeTipe = $input.first().binary.data.mimeType ?? "";

const html = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Alumni ID Card</title>

    <!-- Poppins (works if your PDF generator/browser has internet access) -->
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap" rel="stylesheet">

    <style>
      @page {
        size: 85.598mm 53.975mm;
        margin: 0;
      }

      html, body {
        width: 85.598mm;
        height: 53.975mm;
        margin: 0;
        padding: 0;
        font-family: "Poppins", Arial, sans-serif;
      }
      /* ================= THEME ================= */
      :root {
          ${template}
      }

      /* ================= FRONT CARD ================= */
      * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
      }

      body {
        font-family: 'Arial', sans-serif;
        background: white;
        margin: 0;
        padding: 0;
      }

      /* ID Card Container */
      .id-card {
          width: 85.598mm;
          height: 53.975mm;
          position: relative;
          background: white;
          overflow: hidden;
      }

      .id-background {
          position: absolute;
          width: 100%;
          height: 100%;
          z-index: 1;
      }

      /* Top Section - Complex multi-layer design */
      .bg-top-section {
          position: absolute;
          top: 0;
          left: 0;
          right: 0;
          height: 23%;
          overflow: hidden;
      }

      /* Dark triangle (top left) */
      .bg-triangle-dark {
          position: absolute;
          width: 0;
          height: 0;
          border-style: solid;
          border-width: 100px 0 0 280px;
          border-color: transparent transparent transparent var(--color-triangle-dark);
          top: 0;
          left: 0;
      }

      /* Gradient background (top) */
      .bg-top-gradient {
          position: absolute;
          top: 0;
          left: 0;
          right: 0;
          height: 100%;
          background: linear-gradient(90deg, 
              var(--color-top-medium-gradient) 0%, 
              var(--color-top-medium-gradient) 30%, 
              var(--color-top-light-gradient) 70%, 
              var(--color-top-light-gradient) 100%);
      }

      /* Curved wave element (top right) */
      .bg-wave-top {
          position: absolute;
          top: 0;
          right: 0;
          width: 40%;
          height: 200%;
          background: var(--color-wave-top);
          opacity: 0.5;
          border-radius: 50% 0 0 50%;
          transform: translateX(20%);
      }

