      .bg-footer {
          position: absolute;
          bottom: 0;
          left: 0;
          right: 0;
          height: 13%;
          background: linear-gradient(90deg, 
              var(--color-footer-left) 0%, 
              var(--color-footer-left) 40%, 
              var(--color-footer-right) 100%);
          clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);
      }

      /* Diagonal accent on footer (bottom right) */
      .bg-footer-accent {
          position: absolute;
          bottom: 0;
          right: 0;
          width: 30%;
          height: 100%;
          background: linear-gradient(135deg, 
