          font-size: 4mm;
          font-weight: bold;
          letter-spacing: 0mm;
          text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.5);
      }

      /* Main Content Section */
      .main-content {
          position: absolute;
          top: 15mm;
          left: 5mm;
          right: 5mm;
          display: flex;
          gap: 5mm;
      }

      /* Photo Section */
      .photo-container {
          width: 30mm;
          height: 30mm;
          border: 0.5mm solid var(--photo-border-color);
          border-radius: 1mm;
          overflow: hidden;
          flex-shrink: 0;
          background: white;
          display: flex;
          align-items: center;
