      .alumni-number-overlay {
          position: absolute;
          bottom: 0;
          left: 0;
          right: 0;
          background: rgba(255, 255, 255, 0.95);
          padding: 0.8mm;
          text-align: center;
      }

      .alumni-number {
          font-size: 2.8mm;
          color: #000;
          font-weight: bold;
          letter-spacing: 0.2mm;
      }

      /* Alumni Info Section */
      .alumni-info {
          flex: 1;
          display: flex;
          flex-direction: column;
          justify-content: flex-start;
          padding-top: 3mm;
      }

      .alumni-name {
          font-weight: bold;
          color: #000;
          line-height: 1.15;
          margin-bottom: 1.5mm;
      }

      .name-line-1 {
          display: block;
          font-size: 6mm;
      }

      .name-line-2 {
          display: block;
          font-size: 4mm;
      }

      .program {
          font-size: 2mm;
          color: #333;
