      .footer {
          position: absolute;
          bottom: 1mm;
          left: 0;
          right: 0;
          height: 5mm;
          display: flex;
          align-items: center;
          justify-content: center;
      }

      .footer-title {
          color: white;
          font-size: 4mm;
          font-weight: bold;
          letter-spacing: 0.75mm;
          text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.5);
      }

      /* Print styles */
      @media print {
          body {
              background: white;
              padding: 0;
              margin: 0;
          }

          .id-card {
              box-shadow: none;
              page-break-after: always;
          }
      }

      /* ================= BACK CARD ================= */
      .back-card {
        width:85.598mm;
        height:53.975mm;
        position:relative;
        overflow:hidden;
      }

      .back-border{
        position:absolute;
        inset:0;
        padding:2.2mm;
        background: linear-gradient(
          135deg,
          var(--color-triangle-dark) 0%,
          var(--color-top-medium-gradient) 35%,
          var(--color-top-light-gradient) 65%,
          var(--color-footer-left) 85%,
          var(--color-footer-right) 100%
        );
      }

      .back-safe{
        width:100%;
        height:100%;
        background:#fff;
        padding:3mm;
        display:flex;
        flex-direction:column;
        justify-content: space-between;
      }

      .terms-block{
        flex: 0 0 auto;
      }

      .terms{
        padding-left:4.2mm;
        font-size:2.2mm;
        line-height:1.2;
        color:#111;
      }

      .terms li{
        margin-bottom:0.8mm;
      }

      .bottom-row{
        display:flex;
        justify-content:space-between;
        gap:4mm;
        align-items:flex-end;
      }

      .return-block{
        flex:1;
        font-size:2mm;
        line-height:1.2;
      }

      .return-title{ font-weight:600; margin-bottom:0.8mm; }
      .return-school{ font-weight:700; }
      .return-or{ margin:0.8mm 0; font-weight:700; }

      .signature-block{
        width:34mm;
        text-align:right;
      }

      .sig-line{
        border-bottom:0.35mm solid rgba(0,0,0,0.55);
        height:0;
        width:100%;
      }

      .sig-caption{
        margin-top:1mm;
        font-size:2.5mm;
        color:#444;
      }

      .signature-img{
        width:100%;
        max-height:12mm;
        object-fit:contain;
        margin-bottom:1mm;
      }
    </style>
</head>
<body>
    <!-- ================= FRONT ================= -->
    <div class="id-card">
        <!-- CSS-Based Background - Exact Replica -->
        <div class="id-background">
            <!-- Top Section Layers -->
            <div class="bg-top-section">
                <div class="bg-top-gradient"></div>
                <div class="bg-wave-top"></div>
                <div class="bg-triangle-dark"></div>
            </div>

            <!-- Middle Section -->
            <div class="bg-body"></div>

            <!-- Bottom Section -->
            <div class="bg-footer">
                <div class="bg-footer-accent"></div>
            </div>
        </div>

        <!-- Content Overlay -->
        <div class="id-content">
            <!-- Header -->
            <div class="header">
                <div class="school-logo">
                    <img id="schoolLogo" src="data:${logoPhotoMimeTipe};base64,${logoPhotoBase64}" alt="School Logo">
                </div>
                <div class="school-name" id="schoolName">${school}</div>
            </div>

            <!-- Main Content -->
            <div class="main-content">
                <!-- Photo Container with Alumni Number -->
                <div class="photo-container">
                    <img id="alumniPhoto" src="${idPhotoBase64}" alt="Alumni Photo">
                    <div class="alumni-number-overlay">
                        <div class="alumni-number" id="alumniNumber">${alumniID}</div>
                    </div>
                </div>

                <!-- Alumni Info -->
                <div class="alumni-info">
                    <div class="alumni-name">
                        <span class="name-line-1" id="lastName">${lastName}</span>
                        <span class="name-line-2" id="firstName">${firstName}</span>
                    </div>
                    <div class="program" id="program">${program}</div>
                    <div class="graduation-year" id="graduationYear">Class of ${gradYear}</div>
                </div>
            </div>

            <!-- Footer -->
            <div class="footer">
                <div class="footer-title">ALUMNI ID</div>
            </div>
        </div>
    </div>

    <!-- ================= BACK ================= -->
    <div class="id-card back-card">
      <div class="back-border">
        <div class="back-safe">

          <div class="terms-block">
            <ol class="terms">
              <li>
                This person whose picture and signature appear on this card is a
                <strong>bona fide</strong> member of the ${school} Alumni Association.
              </li>
              <li>This card is non-transferable but replaceable for a fine.</li>
              <li>The holder of this card is entitled to the benefits of the Alumni Association.</li>
              <li>
                This card also ensures the holder to avail of services offered by
                ${school} subject to existing rules and regulations.
              </li>
            </ol>
          </div>

          <div class="bottom-row">

            <div class="return-block">
              <div class="return-title">If found please return to:</div>
              <div class="return-school">${school}</div>
              <div class="return-or">OR</div>
              <div class="return-contact">
                Contact: ${mobile} <br/>
                Email: ${email}
              </div>
            </div>

            <div class="signature-block">
              ${
                idSigBase64
                  ? `<img class="signature-img" src="${idSigBase64}" />`
                  : `<div class="sig-line"></div>`
              }
              <div class="sig-caption">Card Holder’s Signature</div>
            </div>

          </div>
        </div>
      </div>
    </div>
</body>
</html>
`;

return [
